import { Link, useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext"
import { useState } from "react";
import { isNotEmpty, isValidMobile, isValidEmail } from "../utils/validations";

export default function Signup() {
  const { user, signUp, sendOTP, sendEmailVerification } = useAuth();
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [mobile, setMobile] = useState('');
  const [email, setEmail] = useState('');
  const [otp, setOtp] = useState('');
  const [emailOtp, setEmailOtp] = useState('');
  const [error, setError] = useState('');
  const [userId, setUserId] = useState('');

  if(user) {
    navigate('/view');
  }

  const handleSendOTP = (e) => {
    e.preventDefault();
    if(!isNotEmpty(mobile) || !isValidMobile(mobile)) {
      setError('Please enter a valid mobile number')
      return;
    }
    if(!isNotEmpty(email) || !isValidEmail(email)) {
      setError('Please enter a valid email')
      return;
    }
    const success = sendOTP(mobile);
    if(success) {
      setStep(2);
      setError('');
    } else {
      setError('Failed to send OTP');
    }
  }

  const handleVerifyMobileOTP = (e) => {
    e.preventDefault();
    if(!isNotEmpty(otp)) {
      setError('Please enter OTP')
      return;
    }
    const result = signUp(mobile, otp, email);
    if(result.success) {
      setUserId(result.userId);
      setStep(3);
      setError('');
    } else {
      setError(result.message)
    }
  }

  const handleSendEmailVerification = (e) => {
    e.preventDefault();
    const success = sendEmailVerification(email);
    if(success) {
      setStep(4);
      setError('');
    } else {
      setError('Failed to send email verification');
    }
  }

  const handleVerifyEmailOTP = (e) => {
    e.preventDefault();
    if(!isNotEmpty(emailOtp)) {
      setError('Please enter email OTP')
      return;
    }
    const result = verifyEmailOTP(email, emailOtp);
    if(result.success) {
      navigate('/view')
    } else {
      setError('Invalid email OTP')
    }
  }

  return (
    <div className="panel login-panel">
      <h2>Sign Up</h2>
      {step === 1 ? (
        <form onSubmit={handleSendOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="signup-mobile">Mobile Number:</label>
            <input
              id="signup-mobile"
              type="text"
              placeholder="Enter mobile number"
              value={mobile}
              onChange={(e) => setMobile(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label htmlFor="signup-email">Email:</label>
            <input
              id="signup-email"
              type="email"
              placeholder="Enter email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Send Mobile OTP
          </button>
          <p style={{fontSize: '12px', color: '#666'}}>
            OTP will be sent to your mobile number via SMS
          </p>
          <p>
            Already have an account? <Link to="/login">Log in</Link>
          </p>
        </form>
      ) : step === 2 ? (
        <form onSubmit={handleVerifyMobileOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="signup-otp">Mobile OTP:</label>
            <input
              id="signup-otp"
              type="text"
              placeholder="Enter OTP"
              value={otp}
              onChange={(e) => setOtp(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Verify Mobile OTP
          </button>
          <p>
            <button type="button" onClick={() => setStep(1)}>Back</button>
          </p>
        </form>
      ) : step === 3 ? (
        <div className="content-form">
          <p>User ID created: {userId}</p>
          <button className="btn" onClick={handleSendEmailVerification}>
            Send Email Verification
          </button>
          {error && <div className="error">{error}</div>}
        </div>
      ) : (
        <form onSubmit={handleVerifyEmailOTP} className="content-form">
          <div className="form-group">
            <label htmlFor="email-otp">Email OTP:</label>
            <input
              id="email-otp"
              type="text"
              placeholder="Enter email OTP"
              value={emailOtp}
              onChange={(e) => setEmailOtp(e.target.value)}
            />
          </div>
          {error && <div className="error">{error}</div>}
          <button className="btn" type="submit">
            Verify Email OTP
          </button>
          <p>
            <button type="button" onClick={() => setStep(3)}>Back</button>
          </p>
        </form>
      )}
    </div>
  )
}
